DROP TABLE IF EXISTS `Customer`;
CREATE TABLE `Customer` (
  `id` varchar(191) NOT NULL,
  `customerCode` varchar(191) NOT NULL,
  `aadhaarNumber` varchar(191) NOT NULL,
  `aadhaarVerified` tinyint(1) NOT NULL DEFAULT 0,
  `fullName` varchar(191) NOT NULL,
  `dob` datetime(3) DEFAULT NULL,
  `gender` varchar(191) DEFAULT NULL,
  `mobile` varchar(191) NOT NULL,
  `alternateMobile` varchar(191) DEFAULT NULL,
  `email` varchar(191) DEFAULT NULL,
  `panNumber` varchar(191) DEFAULT NULL,
  `address` varchar(191) DEFAULT NULL,
  `currentAddress` varchar(191) DEFAULT NULL,
  `refName` varchar(191) DEFAULT NULL,
  `refMobile` varchar(191) DEFAULT NULL,
  `refRelation` varchar(191) DEFAULT NULL,
  `occupation` varchar(191) DEFAULT NULL,
  `photoUrl` longtext DEFAULT NULL,
  `createdBy` varchar(191) NOT NULL,
  `branchId` varchar(191) NOT NULL,
  `createdAt` datetime(3) NOT NULL DEFAULT current_timestamp(3),
  `updatedAt` datetime(3) NOT NULL,
  `isFraud` tinyint(1) DEFAULT 0,
  `fraudReason` text DEFAULT NULL,
  PRIMARY KEY (`id`),
  UNIQUE KEY `Customer_customerCode_key` (`customerCode`),
  UNIQUE KEY `Customer_aadhaarNumber_key` (`aadhaarNumber`),
  UNIQUE KEY `Customer_mobile_key` (`mobile`),
  KEY `Customer_branchId_fkey` (`branchId`),
  CONSTRAINT `Customer_branchId_fkey` FOREIGN KEY (`branchId`) REFERENCES `Branch` (`id`) ON UPDATE CASCADE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

