DROP TABLE IF EXISTS `GoldItem`;
CREATE TABLE `GoldItem` (
  `id` varchar(191) NOT NULL,
  `transactionId` varchar(191) NOT NULL,
  `goldType` varchar(191) NOT NULL,
  `ornamentName` varchar(191) NOT NULL,
  `grossWeight` double NOT NULL,
  `stoneWeight` double NOT NULL DEFAULT 0,
  `netWeight` double NOT NULL,
  `purity` double NOT NULL,
  `ratePerGram` double NOT NULL,
  `lessPercent` double DEFAULT 0,
  `addAmount` double DEFAULT 0,
  `finalValue` double NOT NULL,
  `notes` varchar(191) DEFAULT NULL,
  `createdAt` datetime(3) NOT NULL DEFAULT current_timestamp(3),
  PRIMARY KEY (`id`),
  KEY `GoldItem_transactionId_fkey` (`transactionId`),
  CONSTRAINT `GoldItem_transactionId_fkey` FOREIGN KEY (`transactionId`) REFERENCES `Transaction` (`id`) ON UPDATE CASCADE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

