DROP TABLE IF EXISTS `Transaction`;
CREATE TABLE `Transaction` (
  `id` varchar(191) NOT NULL,
  `transactionNumber` varchar(191) NOT NULL,
  `customerId` varchar(191) NOT NULL,
  `branchId` varchar(191) NOT NULL,
  `createdBy` varchar(191) NOT NULL,
  `status` enum('PENDING','COMPLETED','CANCELLED') NOT NULL DEFAULT 'PENDING',
  `totalWeight` double DEFAULT NULL,
  `purity` double DEFAULT NULL,
  `marketRate` double DEFAULT NULL,
  `finalAmount` double DEFAULT NULL,
  `paymentMethod` varchar(191) DEFAULT 'CASH',
  `lessPercent` double DEFAULT 0,
  `addAmount` double DEFAULT 0,
  `agreementPdf` varchar(191) DEFAULT NULL,
  `createdAt` datetime(3) NOT NULL DEFAULT current_timestamp(3),
  `updatedAt` datetime(3) NOT NULL,
  PRIMARY KEY (`id`),
  UNIQUE KEY `Transaction_transactionNumber_key` (`transactionNumber`),
  KEY `Transaction_customerId_fkey` (`customerId`),
  KEY `Transaction_branchId_fkey` (`branchId`),
  CONSTRAINT `Transaction_branchId_fkey` FOREIGN KEY (`branchId`) REFERENCES `Branch` (`id`) ON UPDATE CASCADE,
  CONSTRAINT `Transaction_customerId_fkey` FOREIGN KEY (`customerId`) REFERENCES `Customer` (`id`) ON UPDATE CASCADE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

